// AI memory fields
const memoryFields = [
  'relationship_type', 'market_role', 'intent_level',
  'intent_topic', 'open_loop', 'contact_preference', 'short_summary_note'
];

// Enrichment fields
const enrichmentFields = [
  'first_name', 'last_name', 'email', 'phone',
  'address', 'city', 'state', 'postal_code'
];

const allFields = [...memoryFields, ...enrichmentFields];

const changes = {};
let hasChanges = false;

for (const field of allFields) {
  const beforeVal = (before[field] || '').toString().trim();
  const afterVal = (after[field] || '').toString().trim();

  const isBeforeEmpty = !beforeVal || beforeVal === 'unknown' || beforeVal === 'none' || beforeVal === '{}';
  const isAfterEmpty = !afterVal || afterVal === 'unknown' || afterVal === 'none' || afterVal === '{}';

  if (isBeforeEmpty && isAfterEmpty) continue;

  if (beforeVal !== afterVal) {
    changes[field] = { from: isBeforeEmpty ? '(not set)' : beforeVal, to: isAfterEmpty ? '(cleared)' : afterVal };
    hasChanges = true;
  }
}

let noteText = '';
if (hasChanges) {
  const now = new Date();
  const weekLabel = now.getFullYear() + '-W' + String(Math.ceil((now.getDate() + now.getDay()) / 7)).padStart(2, '0');
  const lines = ['AI Memory Updated (' + weekLabel + '):'];
  for (const [field, vals] of Object.entries(changes)) {
    lines.push('  ' + field + ': ' + vals.from + ' -> ' + vals.to);
  }
  if (after.short_summary_note && after.short_summary_note !== 'unknown') {
    lines.push('');
    lines.push('Summary: ' + after.short_summary_note);
