function normalizeStyle(text) {
  if (!text || typeof text !== 'string') return text;
  let s = text;
  s = s.replace(/\s*\u2014\s*/g, ', ');
  s = s.replace(/\s*\u2013\s*/g, ', ');
  s = s.replace(/(?<!\w)-(?!\w)/g, ',');
  s = s.replace(/ ,/g, ',');
  s = s.replace(/!/g, '.');
  s = s.replace(/,\s*,/g, ',');
  s = s.replace(/,\s*\./g, '.');
  s = s.replace(/\.\s*,/g, '.');
  s = s.replace(/  +/g, ' ');
  s = s.replace(/,(\S)/g, ', $1');
  s = s.replace(/\.([A-Z])/g, '. $1');
  s = s.replace(/,\s*$/g, '.');
  return s.trim();
}

